#!/usr/bin/env python3
from pathlib import Path

ROOT = Path.cwd()
required = ["package.json", "app", "components"]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

files = {
    "app/page.tsx": 'import Link from "next/link";\nimport { MatchCard } from "@/components/MatchCard";\nimport { StandingCard } from "@/components/StandingCard";\nimport { formatStartsIn, resultLabel } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches, getNextMatch, getStandings } from "@/lib/scoring";\n\nexport const revalidate = 600;\n\nfunction getLastFinishedMatch(results: Awaited<ReturnType<typeof getFootballDataResults>>["results"]) {\n  const matches = getMatches();\n\n  return matches\n    .filter((match) => results[match.id]?.status === "FINISHED")\n    .sort((a, b) => {\n      const aTime = new Date(`${a.date ?? "1900-01-01"}T00:00:00`).getTime();\n      const bTime = new Date(`${b.date ?? "1900-01-01"}T00:00:00`).getTime();\n      return bTime - aTime;\n    })[0];\n}\n\nfunction leaderText(standings: ReturnType<typeof getStandings>, played: number): string {\n  if (played === 0) return "Todos empiezan igual";\n  const top = standings[0]?.points ?? 0;\n  const tied = standings.filter((row) => row.points === top).length;\n  return tied > 1 ? "Empate en cabeza" : "Líder provisional";\n}\n\nconst podiumMedals = ["🥇", "🥈", "🥉"];\n\nexport default async function HomePage() {\n  const payload = await getFootballDataResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const matches = getMatches();\n  const total = matches.length;\n  const nextMatch = getNextMatch(payload.results);\n  const lastMatch = getLastFinishedMatch(payload.results);\n  const podium = standings.slice(0, 3);\n  const rest = standings.slice(3);\n  const heroMatch = lastMatch ?? nextMatch;\n  const heroResult = heroMatch ? payload.results[heroMatch.id] : undefined;\n\n  return (\n    <section className="screen v8-screen">\n      <header className="v8-hero">\n        <div className="v8-hero-top">\n          <div className="v8-brand">🏆 Mundial 2026</div>\n          <div className="v8-mini-stats">\n            <span>{standings.length} participantes</span>\n            <span>{total} partidos</span>\n          </div>\n        </div>\n\n        {heroMatch ? (\n          <div className="v8-hero-match">\n            <div className="v8-kicker">{lastMatch ? "Último resultado" : "Partido inaugural"}</div>\n            <h1>{heroMatch.home} - {heroMatch.away}</h1>\n            <p>\n              {lastMatch && heroResult\n                ? resultLabel(heroResult)\n                : formatStartsIn(heroMatch.date, heroMatch.timeEt)}\n            </p>\n          </div>\n        ) : (\n          <div className="v8-hero-match">\n            <div className="v8-kicker">Mundial completado</div>\n            <h1>Porra terminada</h1>\n            <p>{played}/{total} partidos puntuados</p>\n          </div>\n        )}\n\n        <div className="v8-hero-actions">\n          <Link href="/partidos">Ver calendario</Link>\n          <Link href="/pronosticos">Ver quinielas</Link>\n        </div>\n      </header>\n\n      {payload.error ? (\n        <div className="system-notice">Actualizando resultados...</div>\n      ) : null}\n\n      {nextMatch ? (\n        <section className="block v8-block">\n          <div className="block-heading">\n            <h2>Próximo partido</h2>\n            <span>{played}/{total} puntuados</span>\n          </div>\n          <MatchCard match={nextMatch} result={payload.results[nextMatch.id]} featured />\n        </section>\n      ) : null}\n\n      {played === 0 ? (\n        <section className="quiet-card v8-empty">\n          <h2>Todo listo.</h2>\n          <p>La clasificación empezará a moverse cuando termine el primer partido.</p>\n        </section>\n      ) : null}\n\n      <section className="block v8-block">\n        <div className="block-heading">\n          <h2>Clasificación</h2>\n          <span>1 punto por acertar</span>\n        </div>\n\n        <div className="leader-note">{leaderText(standings, played)}</div>\n\n        <div className="podium v8-podium">\n          {podium.map((row, index) => (\n            <Link\n              key={row.player}\n              href={`/pronosticos/${encodeURIComponent(row.player)}`}\n              className={`podium-card v8-podium-card rank-${index + 1}`}\n            >\n              <div className="podium-top">{podiumMedals[index]}</div>\n              <div className="podium-name">{row.player}</div>\n              <div className="podium-score">{row.points}</div>\n              <div className="muted">\n                {row.played === 0 ? "Salida" : `${row.correct}/${row.played} · ${row.percentage}%`}\n              </div>\n            </Link>\n          ))}\n        </div>\n\n        <div className="standing-list">\n          {rest.map((row, index) => (\n            <StandingCard key={row.player} row={row} position={index + 4} compact />\n          ))}\n        </div>\n      </section>\n    </section>\n  );\n}\n',
    "app/partidos/page.tsx": 'import { MatchCard } from "@/components/MatchCard";\nimport { formatDateSection, formatLongMatchDate } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches } from "@/lib/scoring";\n\nexport const revalidate = 600;\n\nexport default async function MatchesPage() {\n  const matches = getMatches();\n  const payload = await getFootballDataResults();\n  const played = Object.keys(payload.results).length;\n\n  const grouped = matches.reduce((acc, match) => {\n    const key = match.date ?? "Fecha pendiente";\n    if (!acc[key]) acc[key] = [];\n    acc[key].push(match);\n    return acc;\n  }, {} as Record<string, typeof matches>);\n\n  return (\n    <section className="screen v8-screen">\n      <header className="page-header v8-page-header">\n        <div className="section-label">Calendario</div>\n        <h1>Todos los partidos</h1>\n        <p>{matches.length} partidos · {played} puntuados</p>\n      </header>\n\n      {payload.error ? (\n        <div className="system-notice">Actualizando resultados...</div>\n      ) : null}\n\n      <div className="date-stack">\n        {Object.entries(grouped).map(([date, dayMatches]) => (\n          <section key={date} className="date-section">\n            <div className="date-title">\n              <h2>{formatDateSection(date)}</h2>\n              <span>{formatLongMatchDate(date)}</span>\n            </div>\n            <div className="match-stack">\n              {dayMatches.map((match) => (\n                <MatchCard key={match.id} match={match} result={payload.results[match.id]} />\n              ))}\n            </div>\n          </section>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/pronosticos/page.tsx": 'import Link from "next/link";\nimport { normalizePlayerForUrl } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getPlayerSummaries } from "@/lib/scoring";\n\nexport const revalidate = 600;\n\nexport default async function PredictionsPage() {\n  const payload = await getFootballDataResults();\n  const players = getPlayerSummaries(payload.results);\n\n  return (\n    <section className="screen v8-screen">\n      <header className="page-header v8-page-header">\n        <div className="section-label">{players.length} participantes</div>\n        <h1>Quinielas</h1>\n        <p>Consulta la quiniela de cada participante.</p>\n      </header>\n\n      <div className="player-list v8-player-list">\n        {players.map((row) => (\n          <Link key={row.player} href={`/pronosticos/${normalizePlayerForUrl(row.player)}`} className="player-row v8-player-row">\n            <div className="avatar">{row.player.slice(0, 1)}</div>\n            <div>\n              <div className="player-name">{row.player}</div>\n              <div className="muted">\n                {row.played === 0 ? "Ver quiniela" : `${row.correct} aciertos · ${row.wrong} fallos`}\n              </div>\n            </div>\n            <div className="row-arrow" aria-hidden="true">›</div>\n          </Link>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "components/MatchCard.tsx": 'import { formatMatchDate, formatSpainTimeFromEt, resultLabel } from "@/lib/format";\nimport { getMatchPredictions, signFromResult } from "@/lib/scoring";\nimport type { Match, MatchResult, Pick } from "@/lib/types";\n\nfunction statusLabel(result?: MatchResult): string {\n  if (!result) return "Pendiente";\n  if (result.status === "LIVE") return result.minute ? `En juego · ${result.minute}\'` : "En juego";\n  if (result.status === "FINISHED") return "Finalizado";\n  return "Pendiente";\n}\n\nexport function MatchCard({\n  match,\n  result,\n  featured = false\n}: {\n  match: Match;\n  result?: MatchResult;\n  featured?: boolean;\n}) {\n  const actual = signFromResult(result);\n  const predictions = getMatchPredictions(match.id);\n\n  const grouped = predictions.reduce(\n    (acc, item) => {\n      acc[item.pick].push(item.player);\n      return acc;\n    },\n    { "1": [], X: [], "2": [] } as Record<Pick, string[]>\n  );\n\n  const renderPick = (pick: Pick) => {\n    const names = grouped[pick];\n\n    return (\n      <details className="pick-details">\n        <summary className={actual === pick ? "pick-button is-hit" : "pick-button"}>\n          <span>{pick}</span>\n          <strong>{names.length}</strong>\n        </summary>\n        <div className="pick-panel">\n          <div className="pick-panel-title">Han apostado por el {pick}</div>\n          <div className="pick-names">{names.join(", ")}</div>\n        </div>\n      </details>\n    );\n  };\n\n  const correct = actual ? predictions.filter((item) => item.pick === actual).map((item) => item.player) : [];\n  const wrong = actual ? predictions.filter((item) => item.pick !== actual).map((item) => item.player) : [];\n\n  return (\n    <article className={featured ? "match-card featured v8-match-card" : "match-card v8-match-card"}>\n      <div className="match-topline">\n        <div className="match-kicker">\n          <span>{formatMatchDate(match.date)}</span>\n          <span>Grupo {match.group ?? "—"}</span>\n        </div>\n        <span className={result ? "match-state is-done" : "match-state"}>\n          {statusLabel(result)}\n        </span>\n      </div>\n\n      <div className="match-main">\n        <div className="team home">{match.home}</div>\n        <div className={result ? "score is-done" : "score"}>{resultLabel(result)}</div>\n        <div className="team away">{match.away}</div>\n      </div>\n\n      <div className="match-time">\n        <span>{match.timeEt ? formatSpainTimeFromEt(match.timeEt) : "Hora pendiente"}</span>\n        {match.timeLocal ? <span>{match.timeLocal} local</span> : null}\n        {match.city ? <span>{match.city}</span> : null}\n      </div>\n\n      <div className="pick-row">\n        {renderPick("1")}\n        {renderPick("X")}\n        {renderPick("2")}\n      </div>\n\n      {actual && result?.status === "FINISHED" ? (\n        <div className="v8-result-people">\n          <div>\n            <strong>Acertaron</strong>\n            <span>{correct.length ? correct.join(", ") : "Nadie"}</span>\n          </div>\n          <div>\n            <strong>Fallaron</strong>\n            <span>{wrong.length ? wrong.join(", ") : "Nadie"}</span>\n          </div>\n        </div>\n      ) : null}\n    </article>\n  );\n}\n',
    "components/StandingCard.tsx": 'import Link from "next/link";\nimport type { Standing } from "@/lib/types";\nimport { normalizePlayerForUrl } from "@/lib/format";\n\nconst medals = ["🥇", "🥈", "🥉"];\n\nexport function StandingCard({\n  row,\n  position,\n  compact = false\n}: {\n  row: Standing;\n  position: number;\n  compact?: boolean;\n}) {\n  const subtitle =\n    row.played === 0\n      ? "Sin partidos puntuados"\n      : `${row.correct}/${row.played} aciertos · ${row.percentage}%`;\n\n  const rank = medals[position - 1] ?? position;\n\n  return (\n    <Link\n      href={`/pronosticos/${normalizePlayerForUrl(row.player)}`}\n      className={compact ? "standing-row compact v8-standing-row" : "standing-row v8-standing-row"}\n    >\n      <div className="standing-position">{rank}</div>\n      <div className="standing-person">\n        <div className="standing-name">{row.player}</div>\n        <div className="muted">{subtitle}</div>\n      </div>\n      <div className="standing-points">\n        <strong>{row.points}</strong>\n        <span>pts</span>\n      </div>\n    </Link>\n  );\n}\n',
    "components/BottomNav.tsx": '"use client";\n\nimport Link from "next/link";\nimport { usePathname } from "next/navigation";\n\nconst items = [\n  { href: "/", label: "Clasificación" },\n  { href: "/partidos", label: "Calendario" },\n  { href: "/pronosticos", label: "Quinielas" },\n  { href: "/instalar", label: "Instalar" }\n];\n\nfunction isActive(pathname: string, href: string): boolean {\n  if (href === "/") return pathname === "/";\n  return pathname.startsWith(href);\n}\n\nexport function BottomNav() {\n  const pathname = usePathname();\n\n  return (\n    <nav className="bottom-nav v8-bottom-nav" aria-label="Navegación principal">\n      {items.map((item) => (\n        <Link\n          key={item.href}\n          href={item.href}\n          className={isActive(pathname, item.href) ? "active" : ""}\n        >\n          {item.label}\n        </Link>\n      ))}\n    </nav>\n  );\n}\n',
}

for rel, content in files.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

css_path = ROOT / "app/globals.css"
css = css_path.read_text(encoding="utf-8")
marker = "/* V8 final design */"
if marker not in css:
    css_path.write_text(css.rstrip() + "\n\n" + '/* V8 final design */\n:root {\n  --v8-bg: #fff4d0;\n  --v8-bg-2: #fff9ec;\n  --v8-card: rgba(255, 255, 255, 0.88);\n  --v8-ink: #17120a;\n  --v8-muted: #79694a;\n  --v8-line: rgba(36, 25, 8, 0.12);\n  --v8-gold: #ffb51f;\n  --v8-gold-2: #ffe7a3;\n  --v8-green: #0e8f61;\n  --v8-red: #bd3b2d;\n}\n\nhtml,\nbody {\n  background:\n    radial-gradient(circle at 20% 0%, rgba(255, 184, 38, 0.28), transparent 32%),\n    radial-gradient(circle at 80% 12%, rgba(255, 220, 132, 0.42), transparent 34%),\n    var(--v8-bg);\n  color: var(--v8-ink);\n  font-family:\n    "Nunito",\n    ui-rounded,\n    "Avenir Next",\n    "SF Pro Rounded",\n    -apple-system,\n    BlinkMacSystemFont,\n    "Helvetica Neue",\n    Arial,\n    sans-serif;\n}\n\nbody {\n  min-height: 100dvh;\n}\n\n.screen.v8-screen,\n.screen {\n  max-width: 520px;\n}\n\n.app-header h1,\n.page-header h1,\n.v8-hero h1,\n.block-heading h2,\n.date-title h2,\n.quiet-card h2,\n.podium-name,\n.team,\n.standing-name,\n.player-name {\n  font-family:\n    "Nunito",\n    ui-rounded,\n    "Avenir Next",\n    "SF Pro Rounded",\n    -apple-system,\n    BlinkMacSystemFont,\n    "Helvetica Neue",\n    Arial,\n    sans-serif;\n}\n\n.v8-hero {\n  position: relative;\n  overflow: hidden;\n  margin: 10px 0 18px;\n  padding: 18px;\n  border: 1px solid rgba(50, 35, 8, 0.14);\n  border-radius: 30px;\n  background:\n    linear-gradient(135deg, rgba(255, 188, 45, 0.95), rgba(255, 230, 163, 0.95)),\n    var(--v8-gold);\n  box-shadow: 0 22px 50px rgba(86, 59, 7, 0.16);\n}\n\n.v8-hero::after {\n  content: "";\n  position: absolute;\n  right: -56px;\n  bottom: -78px;\n  width: 190px;\n  height: 190px;\n  border-radius: 999px;\n  background:\n    linear-gradient(90deg, rgba(20, 16, 9, 0.10) 1px, transparent 1px),\n    linear-gradient(rgba(20, 16, 9, 0.10) 1px, transparent 1px);\n  background-size: 22px 22px;\n  transform: rotate(-18deg);\n  opacity: 0.45;\n}\n\n.v8-hero-top,\n.v8-hero-match,\n.v8-hero-actions {\n  position: relative;\n  z-index: 1;\n}\n\n.v8-hero-top {\n  display: flex;\n  justify-content: space-between;\n  gap: 14px;\n  align-items: flex-start;\n  margin-bottom: 22px;\n}\n\n.v8-brand {\n  font-size: 18px;\n  font-weight: 900;\n  letter-spacing: -0.04em;\n}\n\n.v8-mini-stats {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  align-items: flex-end;\n  color: rgba(31, 21, 4, 0.76);\n  font-size: 12px;\n  font-weight: 850;\n}\n\n.v8-kicker,\n.section-label {\n  color: rgba(42, 26, 0, 0.68);\n  font-size: 12px;\n  font-weight: 900;\n  letter-spacing: 0.08em;\n  text-transform: uppercase;\n}\n\n.v8-hero h1 {\n  margin: 6px 0 6px;\n  max-width: 340px;\n  color: #171107;\n  font-size: clamp(33px, 9vw, 48px);\n  line-height: 0.94;\n  font-weight: 950;\n  letter-spacing: -0.075em;\n}\n\n.v8-hero p {\n  margin: 0;\n  color: rgba(31, 21, 4, 0.78);\n  font-size: 17px;\n  font-weight: 850;\n}\n\n.v8-hero-actions {\n  display: flex;\n  gap: 8px;\n  margin-top: 18px;\n}\n\n.v8-hero-actions a {\n  padding: 10px 12px;\n  border: 1px solid rgba(43, 30, 5, 0.15);\n  border-radius: 999px;\n  background: rgba(255, 255, 255, 0.54);\n  color: #241706;\n  font-size: 13px;\n  font-weight: 900;\n  text-decoration: none;\n}\n\n.live-badge {\n  display: none !important;\n}\n\n.system-notice {\n  border: 1px solid rgba(110, 74, 0, 0.18);\n  border-radius: 18px;\n  background: rgba(255, 244, 204, 0.82);\n  color: #7a5300;\n  font-weight: 850;\n}\n\n.block,\n.quiet-card,\n.match-card,\n.player-row,\n.standing-row {\n  border-color: var(--v8-line);\n  background: var(--v8-card);\n  box-shadow: 0 12px 32px rgba(55, 38, 10, 0.08);\n  backdrop-filter: blur(16px);\n}\n\n.v8-empty {\n  background:\n    linear-gradient(135deg, rgba(255, 255, 255, 0.88), rgba(255, 243, 204, 0.92));\n}\n\n.block-heading h2,\n.page-header h1 {\n  font-weight: 950;\n  letter-spacing: -0.055em;\n}\n\n.page-header.v8-page-header {\n  padding: 8px 2px 10px;\n}\n\n.page-header.v8-page-header h1 {\n  margin-top: 4px;\n  font-size: 38px;\n  line-height: 0.96;\n}\n\n.page-header.v8-page-header p {\n  color: var(--v8-muted);\n  font-weight: 750;\n}\n\n.leader-note {\n  display: inline-flex;\n  align-items: center;\n  margin: -2px 0 12px;\n  padding: 8px 11px;\n  border: 1px solid rgba(190, 137, 18, 0.22);\n  border-radius: 999px;\n  background: var(--v8-gold-2);\n  color: #8a5b00;\n  font-size: 13px;\n  font-weight: 950;\n}\n\n.v8-podium {\n  gap: 10px;\n}\n\n.v8-podium-card,\n.podium-card {\n  position: relative;\n  display: grid;\n  grid-template-columns: 56px 1fr auto;\n  align-items: center;\n  gap: 12px;\n  min-height: 82px;\n  border: 1px solid var(--v8-line);\n  border-radius: 24px;\n  background:\n    linear-gradient(135deg, rgba(255, 255, 255, 0.95), rgba(255, 247, 222, 0.90));\n  text-decoration: none;\n  box-shadow: 0 12px 30px rgba(79, 53, 8, 0.08);\n}\n\n.v8-podium-card.rank-1 {\n  border-color: rgba(255, 181, 31, 0.55);\n  background:\n    linear-gradient(135deg, rgba(255, 237, 176, 0.98), rgba(255, 255, 255, 0.92));\n  transform: scale(1.012);\n}\n\n.podium-top {\n  display: grid;\n  place-items: center;\n  width: 50px;\n  height: 50px;\n  border: 1px solid rgba(206, 148, 17, 0.18);\n  border-radius: 18px;\n  background: var(--v8-gold-2);\n  font-size: 27px;\n}\n\n.podium-name {\n  color: var(--v8-ink);\n  font-size: 20px;\n  font-weight: 950;\n  letter-spacing: -0.035em;\n}\n\n.podium-score {\n  color: var(--v8-ink);\n  font-size: 34px;\n  font-weight: 950;\n  letter-spacing: -0.06em;\n}\n\n.v8-standing-row .standing-position {\n  font-size: 18px;\n  font-weight: 950;\n}\n\n.v8-standing-row .standing-name {\n  font-weight: 900;\n  letter-spacing: -0.025em;\n}\n\n.match-card.v8-match-card {\n  border-radius: 26px;\n}\n\n.match-card.featured.v8-match-card {\n  background:\n    linear-gradient(135deg, rgba(255, 255, 255, 0.95), rgba(255, 245, 213, 0.92));\n}\n\n.match-state {\n  font-weight: 900;\n}\n\n.match-state.is-done {\n  background: rgba(14, 143, 97, 0.10);\n  color: var(--v8-green);\n}\n\n.match-main {\n  align-items: center;\n}\n\n.team {\n  font-weight: 900;\n  letter-spacing: -0.04em;\n}\n\n.score {\n  border-radius: 16px;\n  background: rgba(26, 18, 5, 0.06);\n  font-weight: 950;\n}\n\n.score.is-done {\n  background: #17120a;\n  color: #fff7df;\n}\n\n.pick-button {\n  border-color: var(--v8-line);\n  background: rgba(255, 255, 255, 0.68);\n}\n\n.pick-button.is-hit {\n  border-color: rgba(14, 143, 97, 0.25);\n  background: rgba(14, 143, 97, 0.10);\n  color: var(--v8-green);\n}\n\n.pick-panel {\n  border-color: var(--v8-line);\n  border-radius: 18px;\n  background: rgba(255, 255, 255, 0.92);\n}\n\n.pick-panel-title {\n  color: var(--v8-muted);\n  font-size: 12px;\n  font-weight: 900;\n  letter-spacing: 0;\n  text-transform: none;\n}\n\n.v8-result-people {\n  display: grid;\n  gap: 8px;\n  margin-top: 12px;\n  padding-top: 12px;\n  border-top: 1px solid var(--v8-line);\n}\n\n.v8-result-people div {\n  display: grid;\n  gap: 3px;\n}\n\n.v8-result-people strong {\n  color: var(--v8-ink);\n  font-size: 12px;\n  font-weight: 950;\n}\n\n.v8-result-people span {\n  color: var(--v8-muted);\n  font-size: 13px;\n  line-height: 1.35;\n}\n\n.v8-player-row {\n  border-radius: 22px;\n}\n\n.avatar {\n  background: var(--v8-gold-2);\n  color: #7a5300;\n  font-weight: 950;\n}\n\n.bottom-nav.v8-bottom-nav,\n.bottom-nav {\n  border-top-color: var(--v8-line);\n  background: rgba(255, 249, 236, 0.86);\n  backdrop-filter: blur(18px);\n}\n\n.bottom-nav a {\n  border-radius: 999px;\n  font-weight: 900;\n}\n\n.bottom-nav a.active {\n  background: #17120a;\n  color: #fff4d0;\n}\n\n.muted {\n  color: var(--v8-muted);\n}\n\n@media (max-width: 390px) {\n  .v8-hero {\n    padding: 16px;\n    border-radius: 26px;\n  }\n\n  .v8-hero h1 {\n    font-size: 34px;\n  }\n\n  .v8-mini-stats {\n    font-size: 11px;\n  }\n\n  .v8-hero-actions a {\n    padding: 9px 10px;\n    font-size: 12px;\n  }\n}\n', encoding="utf-8")

print("V8 diseño final aplicado.")
print("- Home con hero de evento")
print("- Clasificación más deportiva")
print("- Calendario y quinielas con copy más natural")
print("- Tarjetas y tipografía unificadas")
print("- Conceptos técnicos ocultos")
print("")
print("Ejecuta:")
print("npm run build")
print("git add .")
print("git commit -m 'Apply V8 final design'")
print("git push")
print("npx vercel --prod")
